import{_ as i,a as e,b as l}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as r,o as n,c as t,a2 as o}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Kimlik Doğrulama ve Giriş Cihazı Yönetimi","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Safety/authentication-and-login-devices.md","filePath":"tr-TR/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),m={name:"tr-TR/Safety/authentication-and-login-devices.md"};function d(c,a,k,u,s,p){return n(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="kimlik-dogrulama-ve-giris-cihazı-yonetimi" tabindex="-1">Kimlik Doğrulama ve Giriş Cihazı Yönetimi <a class="header-anchor" href="#kimlik-dogrulama-ve-giris-cihazı-yonetimi" aria-label="Permalink to &quot;Kimlik Doğrulama ve Giriş Cihazı Yönetimi&quot;">​</a></h1><p><code>Authentication Management</code> ve <code>Login Device Management</code>, ImgBed yönetim panelini, herkese açık yükleme girişini ve WebDAV erişimini korur.</p><p>Bu sayfada erişim bilgilerini ayarlayabilir, oturum açmış cihazları inceleyebilir ve gerektiğinde eski oturumları iptal edebilirsiniz.</p><h2 id="nereden-yapılandırılır" tabindex="-1">Nereden Yapılandırılır? <a class="header-anchor" href="#nereden-yapılandırılır" aria-label="Permalink to &quot;Nereden Yapılandırılır?&quot;">​</a></h2><p>Yönetim panelini açın, ardından şuraya gidin:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>Sayfada iki ana alan bulunur:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+i+'" alt="Kimlik doğrulama yönetimi" loading="lazy"></p><h2 id="authentication-management-ne-ise-yarar" tabindex="-1">Authentication Management Ne İşe Yarar? <a class="header-anchor" href="#authentication-management-ne-ise-yarar" aria-label="Permalink to &quot;Authentication Management Ne İşe Yarar?&quot;">​</a></h2><p>Authentication Management erişim kimlik bilgilerini saklar.</p><p>İki tür vardır:</p><ul><li>Kullanıcı tarafı kimlik doğrulama</li><li>Yönetici tarafı kimlik doğrulama</li></ul><h2 id="kullanıcı-tarafı-kimlik-dogrulama" tabindex="-1">Kullanıcı Tarafı Kimlik Doğrulama <a class="header-anchor" href="#kullanıcı-tarafı-kimlik-dogrulama" aria-label="Permalink to &quot;Kullanıcı Tarafı Kimlik Doğrulama&quot;">​</a></h2><p>Kullanıcı tarafı kimlik doğrulama, yükleme parolasıdır.</p><p>Yükleme parolası ayarlandıktan sonra normal ziyaretçilerin yükleme sayfasını kullanmadan önce bu parolayı girmesi gerekir. Herkese açık yükleme sayfasının herkese açık kalmasını istemediğiniz durumlarda kullanışlıdır.</p><p><img src="'+e+'" alt="Kullanıcı giriş sayfası" loading="lazy"></p><h3 id="yukleme-parolasını-ayarlama" tabindex="-1">Yükleme Parolasını Ayarlama <a class="header-anchor" href="#yukleme-parolasını-ayarlama" aria-label="Permalink to &quot;Yükleme Parolasını Ayarlama&quot;">​</a></h3><p>Yükleme parolası yapılandırıldığında:</p><ul><li>Ziyaretçiler yükleme sayfasını kullanmadan önce parolayı girmelidir.</li><li>Yükleme yalnızca parola kabul edildikten sonra kullanılabilir.</li><li>Kullanıcı tarafı cihaz oturumları etkinse ImgBed bu kullanıcı cihazını kaydeder.</li></ul><p>Yükleme parolasını değiştirmek eski kullanıcı tarafı oturumlarını geçersiz kılar. Ziyaretçilerin yeni parolayı tekrar girmesi gerekir.</p><h2 id="yonetici-tarafı-kimlik-dogrulama" tabindex="-1">Yönetici Tarafı Kimlik Doğrulama <a class="header-anchor" href="#yonetici-tarafı-kimlik-dogrulama" aria-label="Permalink to &quot;Yönetici Tarafı Kimlik Doğrulama&quot;">​</a></h2><p>Yönetici tarafı kimlik doğrulama, yönetici kullanıcı adı ve parolası kullanır.</p><p>Bu, yönetim panelini korur. Production kullanımında her zaman yapılandırılması önerilir.</p><p><img src="'+l+'" alt="Yönetici giriş sayfası" loading="lazy"></p><h3 id="yonetici-bilgilerini-ayarlama" tabindex="-1">Yönetici Bilgilerini Ayarlama <a class="header-anchor" href="#yonetici-bilgilerini-ayarlama" aria-label="Permalink to &quot;Yönetici Bilgilerini Ayarlama&quot;">​</a></h3><p>Yönetici kullanıcı adı ve parolası yapılandırıldığında:</p><ul><li>Yönetim panelini açmak için giriş gerekir.</li><li>Başarılı giriş bir yönetici cihaz kaydı oluşturur.</li><li>Login Device Management içinde cihazları inceleyebilir, temizleyebilir veya zorla çevrimdışı bırakabilirsiniz.</li></ul><p>Yönetici kullanıcı adını veya parolasını değiştirmek eski yönetici oturumlarını geçersiz kılar. Yeniden giriş yapmanız gerekir.</p><h2 id="login-device-management-ne-ise-yarar" tabindex="-1">Login Device Management Ne İşe Yarar? <a class="header-anchor" href="#login-device-management-ne-ise-yarar" aria-label="Permalink to &quot;Login Device Management Ne İşe Yarar?&quot;">​</a></h2><p>Login Device Management oturum açmış cihazları gösterir.</p><p>Şunları kontrol etmenize yardımcı olur:</p><ul><li>Hangi cihazların yönetim paneline eriştiği.</li><li>Hangi cihazların kullanıcı tarafı yükleme sayfasına eriştiği.</li><li>Hangi WebDAV istemcilerinin bağlandığı.</li><li>Cihaz oturumunun hâlâ geçerli olup olmadığı.</li><li>Eski cihazların zorla çevrimdışı bırakılıp bırakılmaması gerektiği.</li></ul><p>Sayfada üç sekme bulunur:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="genel-cookie-guvenligi" tabindex="-1">Genel Cookie Güvenliği <a class="header-anchor" href="#genel-cookie-guvenligi" aria-label="Permalink to &quot;Genel Cookie Güvenliği&quot;">​</a></h2><p>Login Device Management üst kısmında genel cookie davranışını ayarlayabilirsiniz.</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>Kullanıcı tarafı girişin kaç gün aktif kalabileceğini belirler.</p><p>Örneğin 14 gün olarak ayarlarsanız ziyaretçilerin genellikle 14 gün boyunca yükleme parolasını yeniden girmesi gerekmez.</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>Yönetici girişinin kaç gün aktif kalabileceğini belirler.</p><p>Örneğin 14 gün olarak ayarlarsanız yöneticilerin genellikle 14 gün boyunca yeniden giriş yapması gerekmez.</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>Secure mode etkin olduğunda tarayıcılar giriş cookie değerlerini yalnızca HTTPS üzerinden gönderir.</p><p>Production HTTPS sitelerinde etkinleştirin. Yerel HTTP testlerinde etkinleştirmeyin; aksi halde &quot;giriş başarılı ama sayfayı yenileyince çıkış yapıyor&quot; gibi bir davranış görebilirsiniz.</p><h2 id="yonetici-giris-cihazları" tabindex="-1">Yönetici Giriş Cihazları <a class="header-anchor" href="#yonetici-giris-cihazları" aria-label="Permalink to &quot;Yönetici Giriş Cihazları&quot;">​</a></h2><p>Admin sekmesi, yönetim paneline giriş yapan cihazları gösterir.</p><p>Cihaz kayıtları yalnızca yönetici bilgileri yapılandırıldıktan ve yönetim paneline giriş formu üzerinden erişildikten sonra görünür.</p><p>Her cihaz kartı şunları gösterebilir:</p><ul><li>Cihaz ve tarayıcı bilgisi</li><li>İlk giriş IP adresi</li><li>Son aktif IP adresi</li><li>Giriş zamanı</li><li>Son aktif zaman</li><li>Sona erme zamanı</li><li>Geçerli durum</li></ul><p>Tanımadığınız bir cihaz görürseniz <code>Force Offline</code> ile oturumu geçersiz kılın.</p><h2 id="eski-cihazları-temizleme" tabindex="-1">Eski Cihazları Temizleme <a class="header-anchor" href="#eski-cihazları-temizleme" aria-label="Permalink to &quot;Eski Cihazları Temizleme&quot;">​</a></h2><p><code>Clean Up Old Devices</code>, geçerli sekmedeki eski giriş kayıtlarını toplu olarak siler.</p><p>Başka cihazlarda eski oturumların hâlâ aktif olabileceğinden şüpheleniyorsanız kullanın.</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> tek bir cihaz oturumunu geçersiz kılar.</p><p>Bir cihaz zorla çevrimdışı bırakıldıktan sonra:</p><ul><li>Yönetici cihazlarının yeniden giriş yapması gerekir.</li><li>Kullanıcı tarafı cihazlarının yükleme parolasını yeniden girmesi gerekir.</li><li>WebDAV istemcilerinin yeniden kimlik doğrulaması yapması gerekir.</li></ul><p>Süresi dolmuş veya geçersiz cihazlar da kaldırılabilir.</p><h2 id="gecerli-cihazdan-cıkıs" tabindex="-1">Geçerli Cihazdan Çıkış <a class="header-anchor" href="#gecerli-cihazdan-cıkıs" aria-label="Permalink to &quot;Geçerli Cihazdan Çıkış&quot;">​</a></h2><p>Geçerli cihaz kartı <code>Current Device</code> olarak işaretlenir.</p><p>Geçerli cihazdan çıkış yaptıktan sonra:</p><ul><li>Geçerli yönetici oturumu kapatılır.</li><li>Geçerli kullanıcı tarafı oturumu kapatılır.</li></ul><p>Bu alanı kullanmaya devam etmek için yeniden giriş yapmanız gerekir.</p>',65)])])}const f=r(m,[["render",d]]);export{y as __pageData,f as default};
